package com.example.documentviewer;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.FileProvider;

public class DocumentOpenActivity extends AppCompatActivity {

    private static final String MIME_PDF = "application/pdf";
    private static final String MIME_JPEG = "image/jpeg";
    private static final String MIME_PNG = "image/png";
    private static final String MIME_WEBP = "image/webp";
    private static final String MIME_GIF = "image/gif";

    private ImageView imageView;
    private TextView textView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);

        textView = new TextView(this);
        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);

        root.addView(textView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        root.addView(imageView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.MATCH_PARENT
        ));

        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null) {
            textView.setText("No document received.");
            return;
        }

        Uri uri = intent.getData();
        if (uri == null && intent.getClipData() != null && intent.getClipData().getItemCount() > 0) {
            uri = intent.getClipData().getItemAt(0).getUri();
        }

        if (uri == null) {
            textView.setText("No file URI found in intent.");
            return;
        }

        String mimeType = getContentResolver().getType(uri);
        if (mimeType == null) {
            mimeType = guessMimeType(uri);
        }

        if (mimeType != null && mimeType.startsWith("image/")) {
            textView.setText(uri.toString());
            imageView.setImageURI(uri);
            imageView.setVisibility(ImageView.VISIBLE);
        } else if (MIME_PDF.equals(mimeType)) {
            textView.setText("PDF document: " + uri.toString());
            imageView.setImageDrawable(null);
            imageView.setVisibility(ImageView.GONE);
        } else {
            textView.setText("Unsupported document type: " + mimeType + "\nURI: " + uri.toString());
            imageView.setImageDrawable(null);
            imageView.setVisibility(ImageView.GONE);
        }
    }

    private String guessMimeType(Uri uri) {
        String path = uri.getLastPathSegment();
        if (path == null) return null;

        int dot = path.lastIndexOf('.');
        if (dot < 0 || dot == path.length() - 1) return null;

        String ext = path.substring(dot + 1).toLowerCase();
        if ("pdf".equals(ext)) return MIME_PDF;
        if ("jpg".equals(ext) || "jpeg".equals(ext)) return MIME_JPEG;
        if ("png".equals(ext)) return MIME_PNG;
        if ("webp".equals(ext)) return MIME_WEBP;
        if ("gif".equals(ext)) return MIME_GIF;

        return MimeTypeMap.getSingleton().getMimeTypeFromExtension(ext);
    }
}

